// Generated by the Unit Test Generator (pipeline stage 6) for batch 001.
// Scope: src/auth.js changes only (SEC-001). FIRST-compliant per skills/unit-tests-FIRST.md —
// ADMIN_TOKEN env var is set per test and restored afterwards (Independent/Repeatable).

import { test, beforeEach, afterEach } from "node:test";
import assert from "node:assert/strict";
import { isAdmin } from "../../src/auth.js";

const originalToken = process.env.ADMIN_TOKEN;

beforeEach(() => {
  delete process.env.ADMIN_TOKEN;
});

afterEach(() => {
  if (originalToken === undefined) delete process.env.ADMIN_TOKEN;
  else process.env.ADMIN_TOKEN = originalToken;
});

test("isAdmin: correct token with ADMIN_TOKEN set → true", () => {
  process.env.ADMIN_TOKEN = "test-secret-123";
  assert.equal(isAdmin("test-secret-123"), true);
});

test("isAdmin: wrong token of same length → false", () => {
  process.env.ADMIN_TOKEN = "test-secret-123";
  assert.equal(isAdmin("test-secret-456"), false);
});

test("isAdmin: wrong token of different length → false (regression SEC-001)", () => {
  process.env.ADMIN_TOKEN = "test-secret-123";
  assert.equal(isAdmin("guess123"), false);
});

test("isAdmin: ADMIN_TOKEN unset → false even for formerly hardcoded value (fail closed)", () => {
  assert.equal(isAdmin("spendlite-admin-2026"), false);
});

test("isAdmin: non-string token (missing header) → false", () => {
  process.env.ADMIN_TOKEN = "test-secret-123";
  assert.equal(isAdmin(undefined), false);
});

test("isAdmin: empty-string token → false", () => {
  process.env.ADMIN_TOKEN = "test-secret-123";
  assert.equal(isAdmin(""), false);
});
